class Solution {
    class Pair{
        int value,index;
        Pair(int v,int i){value=v;index=i;}
    }

    int[] ans;

    public List<Integer> countSmaller(int[] nums){
        ans=new int[nums.length];
        Pair[] arr=new Pair[nums.length];
        for(int i=0;i<nums.length;i++)
            arr[i]=new Pair(nums[i],i);
        mergeSort(arr,0,nums.length-1);
        List<Integer> res=new ArrayList<>();
        for(int x:ans) res.add(x);
        return res;
    }

    private void mergeSort(Pair[] arr,int left,int right){
        if(left>=right) return;
        int mid=(left+right)/2;
        mergeSort(arr,left,mid);
        mergeSort(arr,mid+1,right);
        merge(arr,left,mid,right);
    }

    private void merge(Pair[] arr,int left,int mid,int right){
        List<Pair> temp=new ArrayList<>();
        int i=left,j=mid+1;
        int rightCounter=0;

        while(i<=mid && j<=right){
            if(arr[j].value<arr[i].value){
                rightCounter++;
                temp.add(arr[j++]);
            }else{
                ans[arr[i].index]+=rightCounter;
                temp.add(arr[i++]);
            }
        }

        while(i<=mid){
            ans[arr[i].index]+=rightCounter;
            temp.add(arr[i++]);
        }

        while(j<=right)
            temp.add(arr[j++]);

        for(int k=left;k<=right;k++)
            arr[k]=temp.get(k-left);
    }
}
